// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.IndependentExistsBranchReorderSafety.Analysis;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.IndependentExistsBranchReorderSafety.BaseFacts;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.IndependentExistsBranchReorderSafety.BranchFacts;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.IndependentExistsBranchReorderSafety.BranchKind;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.IndependentExistsBranchReorderSafety.Rejection;
import org.junit.jupiter.api.Test;

class IndependentExistsBranchReorderSafetyTest {

	@Test
	void nullableCorrelationIsRejectedBeforeBranchReordering() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask shared = universe.maskOf(Set.of("shared"));
		BindingMask nullable = universe.maskOf(Set.of("nullable"));
		BaseFacts base = new BaseFacts(shared.union(nullable), shared, true, false);

		Analysis analysis = IndependentExistsBranchReorderSafety.analyze(base, List.of(
				branch(BranchKind.EXISTS, nullable, BindingMask.EMPTY, nullable),
				branch(BranchKind.NOT_EXISTS, shared, BindingMask.EMPTY, shared)));

		assertFalse(analysis.safe());
		assertEquals(Rejection.UNASSURED_CORRELATION, analysis.rejection());
		assertEquals(0, analysis.branchIndex());
	}

	@Test
	void siblingOnlyInputIsCrossBranchDependencyRatherThanGenericUnassuredInput() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask shared = universe.maskOf(Set.of("shared"));
		BindingMask siblingOnly = universe.maskOf(Set.of("siblingOnly"));
		BaseFacts base = new BaseFacts(shared, shared, true, false);

		Analysis analysis = IndependentExistsBranchReorderSafety.analyze(base, List.of(
				branch(BranchKind.EXISTS, shared, BindingMask.EMPTY, shared.union(siblingOnly)),
				branch(BranchKind.NOT_EXISTS, shared, siblingOnly, shared)));

		assertFalse(analysis.safe());
		assertEquals(Rejection.CROSS_BRANCH_DEPENDENCY, analysis.rejection());
		assertEquals(1, analysis.branchIndex());
		assertEquals(0, analysis.otherBranchIndex());
	}

	@Test
	void unsafeOrBarrierStructureFailsClosed() {
		BindingUniverse universe = BindingUniverse.create();
		BindingMask shared = universe.maskOf(Set.of("shared"));
		BaseFacts safeBase = new BaseFacts(shared, shared, true, false);
		BranchFacts safe = branch(BranchKind.EXISTS, shared, BindingMask.EMPTY, shared);

		Analysis unsafe = IndependentExistsBranchReorderSafety.analyze(safeBase,
				List.of(safe, new BranchFacts(BranchKind.NOT_EXISTS, shared, BindingMask.EMPTY, shared, false, false)));
		assertEquals(Rejection.UNSAFE_STRUCTURE, unsafe.rejection());

		Analysis barrier = IndependentExistsBranchReorderSafety.analyze(safeBase,
				List.of(safe, new BranchFacts(BranchKind.NOT_EXISTS, shared, BindingMask.EMPTY, shared, true, true)));
		assertEquals(Rejection.SEMANTIC_BARRIER, barrier.rejection());
	}

	private static BranchFacts branch(BranchKind kind, BindingMask correlation, BindingMask required,
			BindingMask possible) {
		return new BranchFacts(kind, correlation, required, possible, true, false);
	}
}
